/* eslint-disable no-undef */
import { isWebkit2 } from './utils';

/**
 * Force open keyboard in WebViews
 * @param {HTMLInputElement} input
 */
const open = (input) => {
  if (!isWebkit2()) {
    return;
  }

  const { inputMode, type, id } = input;

  let inputType = inputMode || type;

  if (type === 'tel') {
    inputType = 'phone';
  }
  if (inputMode === 'decimal') {
    inputType = 'numberDecimal';
  }

  if (typeof MobileWebKit?.actions.openKeyboard === 'function') {
    MobileWebKit.actions.openKeyboard(id, inputType).catch(() => { });
  }
};

export {
  open,
};
